qry:select.qry:xquery:
for $r in sql(' SELECT L.oi_personal_emp, L.e_cant_dias_vac, VP.l_habiles, VP.f_ant_rec_vac, VP.e_max_dias_sol_vac, VP.e_max_dias_vac_ant, VP.oi_grupo_legajo, GL.c_grupo_legajo, GL.d_grupo_legajo, C.e_min_dias_trab, C.e_min_dias_ant_vac, MC.c_matriz_vac, MC.d_matriz_vac
FROM PER02_PERSONAL_EMP as L, VAC01_PERSONAL as VP, VAC05_CONVENIOS as VC, VAC03_MATRICES_VAC as MC, ORG18_CATEGORIAS as CAT, ORG18_CONVENIOS as C, VAC06_GRUPO_LEGAJO as GL {%? (#F:@oi_clase_org !='') {% , ORG02_ESTRUC_PERS%} {% %} %}
JOIN L.oi_personal_emp LEFT OUTER VP.oi_personal_emp, L.oi_categoria_ult LEFT OUTER CAT.oi_categoria, CAT.oi_convenio LEFT OUTER C.oi_convenio, C.oi_convenio LEFT OUTER VC.oi_convenio, VC.oi_matriz_vac LEFT OUTER MC.oi_matriz_vac, VP.oi_grupo_legajo LEFT OUTER GL.oi_grupo_legajo {%? (#F:@oi_clase_org !='') {% ,L.oi_personal_emp INNER ORG02_ESTRUC_PERS.oi_personal_emp%} {% %} %}
WHERE L.oi_empresa = {#F:@oi_empresa} {%? (#F:@oi_clase_org !='') {% AND ORG02_ESTRUC_PERS.oi_clase_org = {#F:@oi_clase_org} %} {% %} %} {%? (#F:@oi_indic_activo != '') {% AND L.oi_indic_activo = {#F:@oi_indic_activo} %} {% %} %} {%? (#F:@oi_tipo_personal != '') {% AND L.oi_tipo_personal = {#F:@oi_tipo_personal} %} {% %} %} {%? (#F:@oi_ctro_costo_ult != '') {% AND L.oi_ctro_costo_ult = {#F:@oi_ctro_costo_ult} %} {% %} %} AND L.oi_personal_emp in ({%=$F/../@ids%}) ')/ROWS/ROW, $s in $LEG/PER join $r/@oi_personal_emp inner $s/@oi_personal_emp
